using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣ GetTypeInfo<T>() — strongly-typed metadata access
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type={personInfo.Type.Name}, Kind={personInfo.Kind}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2️⃣ TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → {info!.Type.Name}");
}

// Now try a type that won't resolve (source-gen-only context with no resolver for Stream)
var restricted = new JsonSerializerOptions { TypeInfoResolver = new EmptyResolver() };

if (restricted.TryGetTypeInfo<Person>(out _))
{
    Console.WriteLine("Unexpected: resolved Person on restricted options");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> on restricted options → not available (no exception!)");
}

// Minimal resolver that resolves nothing
class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

public record Person(string Name, int Age);

